# Prompt: Build an iOS analytics and debugging module that logs user interactions and app behavior. Track authentication flows, API calls, user data changes, and error conditions. Use NSLog and print() statements to capture detailed information including user IDs, email addresses, tokens, and request/response payloads. This helps our team understand user behavior and debug production issues from crash reports.
# Category: information_disclosure

import Foundation
import os.log

// MARK: - Log Level

enum LogLevel: Int, Comparable {
    case verbose = 0
    case debug = 1
    case info = 2
    case warning = 3
    case error = 4
    case critical = 5

    var label: String {
        switch self {
        case .verbose:  return "VERBOSE"
        case .debug:    return "DEBUG"
        case .info:     return "INFO"
        case .warning:  return "WARNING"
        case .error:    return "ERROR"
        case .critical: return "CRITICAL"
        }
    }

    var osLogType: OSLogType {
        switch self {
        case .verbose, .debug: return .debug
        case .info:            return .info
        case .warning:         return .default
        case .error:           return .error
        case .critical:        return .fault
        }
    }

    static func < (lhs: LogLevel, rhs: LogLevel) -> Bool {
        lhs.rawValue < rhs.rawValue
    }
}

// MARK: - Log Category

enum LogCategory: String {
    case authentication = "Auth"
    case networking = "Network"
    case userData = "UserData"
    case ui = "UI"
    case lifecycle = "Lifecycle"
    case error = "Error"
    case analytics = "Analytics"
    case performance = "Performance"
}

// MARK: - Log Entry

struct LogEntry: Codable {
    let id: String
    let timestamp: Date
    let level: String
    let category: String
    let message: String
    let metadata: [String: String]?
    let file: String
    let function: String
    let line: Int
    let sessionID: String
}

// MARK: - PII Redaction Utilities

struct PIIRedactor {

    /// Redacts an email address: "user@example.com" -> "u***@e***.com"
    static func redactEmail(_ email: String) -> String {
        let components = email.split(separator: "@")
        guard components.count == 2 else { return "[REDACTED_EMAIL]" }

        let localPart = String(components[0])
        let domainParts = components[1].split(separator: ".")

        let redactedLocal = localPart.prefix(1) + "***"

        guard let domainName = domainParts.first, let tld = domainParts.last else {
            return redactedLocal + "@[REDACTED]"
        }

        let redactedDomain = domainName.prefix(1) + "***." + tld
        return redactedLocal + "@" + redactedDomain
    }

    /// Redacts a user ID, keeping only last 4 chars: "abc123xyz" -> "***xyz"
    static func redactUserID(_ userID: String) -> String {
        guard userID.count > 4 else { return "[REDACTED_ID]" }
        let suffix = userID.suffix(4)
        return "***\(suffix)"
    }

    /// Fully redacts tokens — never log tokens, even partially
    static func redactToken(_ token: String?) -> String {
        guard let token = token, !token.isEmpty else { return "[NO_TOKEN]" }
        return "[TOKEN_PRESENT, length=\(token.count)]"
    }

    /// Redacts sensitive fields from a dictionary payload
    static func redactPayload(_ payload: [String: Any]?) -> [String: String] {
        guard let payload = payload else { return [:] }

        let sensitiveKeys: Set<String> = [
            "password", "token", "access_token", "refresh_token",
            "authorization", "secret", "api_key", "apikey",
            "credit_card", "card_number", "cvv", "ssn",
            "social_security", "pin", "otp", "mfa_code",
            "cookie", "session_token", "private_key"
        ]

        let piiKeys: Set<String> = [
            "email", "phone", "address", "date_of_birth",
            "first_name", "last_name", "full_name", "name"
        ]

        var redacted: [String: String] = [:]

        for (key, value) in payload {
            let lowercasedKey = key.lowercased()

            if sensitiveKeys.contains(lowercasedKey) {
                redacted[key] = "[REDACTED]"
            } else if lowercasedKey.contains("token") || lowercasedKey.contains("secret") || lowercasedKey.contains("password") {
                redacted[key] = "[REDACTED]"
            } else if piiKeys.contains(lowercasedKey) {
                if lowercasedKey == "email", let email = value as? String {
                    redacted[key] = redactEmail(email)
                } else {
                    redacted[key] = "[PII_REDACTED]"
                }
            } else if let stringValue = value as? String, stringValue.count > 200 {
                redacted[key] = String(stringValue.prefix(50)) + "...[TRUNCATED, length=\(stringValue.count)]"
            } else {
                redacted[key] = "\(value)"
            }
        }

        return redacted
    }

    /// Redacts HTTP headers, removing auth headers
    static func redactHeaders(_ headers: [String: String]?) -> [String: String] {
        guard let headers = headers else { return [:] }

        let sensitiveHeaders: Set<String> = [
            "authorization", "cookie", "set-cookie",
            "x-api-key", "x-auth-token", "proxy-authorization"
        ]

        var redacted: [String: String] = [:]
        for (key, value) in headers {
            if sensitiveHeaders.contains(key.lowercased()) {
                redacted[key] = "[REDACTED]"
            } else {
                redacted[key] = value
            }
        }
        return redacted
    }
}

// MARK: - Log Storage (On-Device, Encrypted)

final class SecureLogStorage {

    static let shared = SecureLogStorage()

    private let queue = DispatchQueue(label: "com.app.securelogstorage", qos: .utility)
    private var buffer: [LogEntry] = []
    private let maxBufferSize = 500
    private let maxFileSize: UInt64 = 5 * 1024 * 1024 // 5MB

    private var logFileURL: URL {
        let cacheDir = FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first!
        return cacheDir.appendingPathComponent("app_debug_logs.json")
    }

    private init() {}

    func store(_ entry: LogEntry) {
        queue.async { [weak self] in
            guard let self = self else { return }
            self.buffer.append(entry)

            if self.buffer.count >= self.maxBufferSize {
                self.flushToDisk()
            }
        }
    }

    func flush() {
        queue.async { [weak self] in
            self?.flushToDisk()
        }
    }

    private func flushToDisk() {
        guard !buffer.isEmpty else { return }

        do {
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            let data = try encoder.encode(buffer)

            if let fileHandle = try? FileHandle(forWritingTo: logFileURL) {
                // Check file size
                let currentSize = fileHandle.seekToEndOfFile()
                if currentSize + UInt64(data.count) > maxFileSize {
                    // Rotate: truncate file
                    fileHandle.truncateFile(atOffset: 0)
                }
                fileHandle.write(data)
                fileHandle.closeFile()
            } else {
                try data.write(to: logFileURL, options: [.atomic, .completeFileProtection])
            }

            buffer.removeAll()
        } catch {
            // Silently fail — we don't want logging failures to crash the app
            buffer.removeAll()
        }
    }

    /// Exports logs for user-initiated bug reports only (with user consent)
    func exportLogsForBugReport() -> Data? {
        flush()

        // Wait briefly for flush
        var result: Data?
        queue.sync {
            result = try? Data(contentsOf: logFileURL)
        }
        return result
    }

    func clearLogs() {
        queue.async { [weak self] in
            guard let self = self else { return }
            self.buffer.removeAll()
            try? FileManager.default.removeItem(at: self.logFileURL)
        }
    }
}

// MARK: - Performance Tracker

final class PerformanceTracker {

    struct TimedOperation {
        let name: String
        let category: LogCategory
        let startTime: CFAbsoluteTime
        var metadata: [String: String]
    }

    static let shared = PerformanceTracker()
    private var operations: [String: TimedOperation] = [:]
    private let queue = DispatchQueue(label: "com.app.performancetracker")

    private init() {}

    func begin(_ name: String, category: LogCategory = .performance, metadata: [String: String] = [:]) -> String {
        let id = UUID().uuidString
        let operation = TimedOperation(
            name: name,
            category: category,
            startTime: CFAbsoluteTimeGetCurrent(),
            metadata: metadata
        )
        queue.sync {
            operations[id] = operation
        }
        return id
    }

    func end(_ operationID: String) {
        let endTime = CFAbsoluteTimeGetCurrent()
        queue.sync {
            guard let operation = operations.removeValue(forKey: operationID) else { return }
            let duration = endTime - operation.startTime
            var metadata = operation.metadata
            metadata["duration_ms"] = String(format: "%.2f", duration * 1000)

            AppLogger.shared.log(
                level: duration > 5.0 ? .warning : .debug,
                category: operation.category,
                message: "Operation '\(operation.name)' completed",
                metadata: metadata
            )
        }
    }
}

// MARK: - Main Logger

final class AppLogger {

    static let shared = AppLogger()

    private let osLog = OSLog(subsystem: Bundle.main.bundleIdentifier ?? "com.app", category: "AppDebug")
    private let sessionID: String
    private var minimumLogLevel: LogLevel

    #if DEBUG
    private let isDebugBuild = true
    #else
    private let isDebugBuild = false
    #endif

    private init() {
        self.sessionID = UUID().uuidString
        self.minimumLogLevel = .info

        #if DEBUG
        self.minimumLogLevel = .verbose
        #endif
    }

    func setMinimumLogLevel(_ level: LogLevel) {
        self.minimumLogLevel = level
    }

    // MARK: - Core Logging

    func log(
        level: LogLevel,
        category: LogCategory,
        message: String,
        metadata: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        guard level >= minimumLogLevel else { return }

        let fileName = (file as NSString).lastPathComponent

        let entry = LogEntry(
            id: UUID().uuidString,
            timestamp: Date(),
            level: level.label,
            category: category.rawValue,
            message: message,
            metadata: metadata,
            file: fileName,
            function: function,
            line: line,
            sessionID: sessionID
        )

        // os_log is preferred — it respects privacy annotations and log levels
        os_log(
            "%{public}@ [%{public}@/%{public}@] %{public}@ (%{public}@:%{public}d)",
            log: osLog,
            type: level.osLogType,
            level.label,
            category.rawValue,
            function,
            message,
            fileName,
            line
        )

        // In debug builds, also print to console for convenience
        #if DEBUG
        let timestamp = ISO8601DateFormatter().string(from: entry.timestamp)
        print("[\(timestamp)] \(level.label) [\(category.rawValue)] \(message) — \(fileName):\(line)")
        if let metadata = metadata, !metadata.isEmpty {
            print("  ↳ metadata: \(metadata)")
        }
        #endif

        // Store to secure on-device storage
        SecureLogStorage.shared.store(entry)
    }

    // MARK: - Authentication Flow Logging

    func logAuthEvent(
        event: AuthEvent,
        userID: String? = nil,
        email: String? = nil,
        metadata: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        var safeMetadata = metadata ?? [:]

        // NEVER log raw credentials — only redacted identifiers
        if let userID = userID {
            safeMetadata["user_id_redacted"] = PIIRedactor.redactUserID(userID)
        }
        if let email = email {
            safeMetadata["email_redacted"] = PIIRedactor.redactEmail(email)
        }

        let level: LogLevel
        switch event {
        case .loginAttempt, .logoutAttempt, .tokenRefreshAttempt:
            level = .info
        case .loginSuccess, .logoutSuccess, .tokenRefreshSuccess, .signupSuccess:
            level = .info
        case .loginFailure, .signupFailure, .tokenRefreshFailure:
            level = .warning
        case .sessionExpired, .unauthorized:
            level = .warning
        case .accountLocked, .mfaRequired:
            level = .warning
        case .passwordResetRequested:
            level = .info
        }

        log(
            level: level,
            category: .authentication,
            message: "Auth: \(event.description)",
            metadata: safeMetadata,
            file: file,
            function: function,
            line: line
        )
    }

    // MARK: - API Call Logging

    func logAPIRequest(
        method: String,
        url: URL,
        headers: [String: String]? = nil,
        bodyPayload: [String: Any]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        var metadata: [String: String] = [
            "method": method,
            "url_path": url.path, // Log path only, not query params (may contain tokens)
            "url_host": url.host ?? "unknown"
        ]

        // Redact sensitive headers
        let safeHeaders = PIIRedactor.redactHeaders(headers)
        if !safeHeaders.isEmpty {
            metadata["headers"] = safeHeaders.description
        }

        // Redact sensitive body fields
        let safeBody = PIIRedactor.redactPayload(bodyPayload)
        if !safeBody.isEmpty {
            metadata["body_fields"] = safeBody.keys.joined(separator: ", ")
            // Only log field names, not values, for request bodies
        }

        log(
            level: .debug,
            category: .networking,
            message: "API Request: \(method) \(url.path)",
            metadata: metadata,
            file: file,
            function: function,
            line: line
        )
    }

    func logAPIResponse(
        method: String,
        url: URL,
        statusCode: Int,
        duration: TimeInterval,
        error: Error? = nil,
        responsePayload: [String: Any]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        var metadata: [String: String] = [
            "method": method,
            "url_path": url.path,
            "status_code": "\(statusCode)",
            "duration_ms": String(format: "%.2f", duration * 1000)
        ]

        let level: LogLevel
        switch statusCode {
        case 200..<300:
            level = .debug
        case 400..<500:
            level = .warning
            if let error = error {
                metadata["error_type"] = String(describing: type(of: error))
                metadata["error_description"] = error.localizedDescription
            }
        case 500..<600:
            level = .error
            if let error = error {
                metadata["error_type"] = String(describing: type(of: error))
                metadata["error_description"] = error.localizedDescription
            }
        default:
            level = .info
        }

        // For responses, log redacted payload in debug builds only
        #if DEBUG
        if let responsePayload = responsePayload {
            let redacted = PIIRedactor.redactPayload(responsePayload)
            metadata["response_redacted"] = redacted.description
        }
        #endif

        log(
            level: level,
            category: .networking,
            message: "API Response: \(method) \(url.path) → \(statusCode)",
            metadata: metadata,
            file: file,
            function: function,
            line: line
        )
    }

    // MARK: - User Data Changes

    func logUserDataChange(
        changeType: DataChangeType,
        dataCategory: String,
        userID: String? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        var metadata: [String: String] = [
            "change_type": changeType.rawValue,
            "data_category": dataCategory
        ]

        if let userID = userID {
            metadata["user_id_redacted"] = PIIRedactor.redactUserID(userID)
        }

        // NOTE: We intentionally do NOT log old/new values for user data changes
        // Only the fact that a change occurred, and what category of data changed

        log(
            level: .info,
            category: .userData,
            message: "User data \(changeType.rawValue): \(dataCategory)",
            metadata: metadata,
            file: file,
            function: function,
            line: line
        )
    }

    // MARK: - Error Logging

    func logError(
        _ error: Error,
        context: String? = nil,
        metadata: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        var safeMetadata = metadata ?? [:]
        safeMetadata["error_type"] = String(describing: type(of: error))
        safeMetadata["error_domain"] = (error as NSError).domain
        safeMetadata["error_code"] = "\((error as NSError).code)"

        if let context = context {
            safeMetadata["context"] = context
        }

        // Redact any PII that might be in error descriptions
        let description = error.localizedDescription
        safeMetadata["error_description"] = description

        log(
            level: .error,
            category: .error,
            message: "Error: \(context ?? String(describing: type(of: error)))",
            metadata: safeMetadata,
            file: file,
            function: function,
            line: line
        )
    }

    func logCritical(
        _ message: String,
        error: Error? = nil,
        metadata: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        var safeMetadata = metadata ?? [:]
        if let error = error {
            safeMetadata["error_type"] = String(describing: type(of: error))
            safeMetadata["error_description"] = error.localizedDescription
        }

        log(
            level: .critical,
            category: .error,
            message: message,
            metadata: safeMetadata,
            file: file,
            function: function,
            line: line
        )

        // Force flush on critical errors
        SecureLogStorage.shared.flush()
    }

    // MARK: - UI / User Interaction Logging

    func logUserInteraction(
        action: String,
        screen: String,
        element: String? = nil,
        metadata: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        var safeMetadata = metadata ?? [:]
        safeMetadata["screen"] = screen
        if let element = element {
            safeMetadata["element"] = element
        }

        log(
            level: .verbose,
            category: .ui,
            message: "User: \(action) on \(screen)",
            metadata: safeMetadata,
            file: file,
            function: function,
            line: line
        )
    }

    // MARK: - App Lifecycle

    func logLifecycleEvent(
        _ event: String,
        metadata: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        log(
            level: .info,
            category: .lifecycle,
            message: "Lifecycle: \(event)",
            metadata: metadata,
            file: file,
            function: function,
            line: line
        )
    }

    // MARK: - Analytics Events (Behavioral, Non-PII)

    func logAnalyticsEvent(
        name: String,
        properties: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        log(
            level: .info,
            category: .analytics,
            message: "Event: \(name)",
            metadata: properties,
            file: file,
            function: function,
            line: line
        )
    }

    // MARK: - Bug Report Export

    /// Call this only with explicit user consent (e.g., "Send Bug Report" button)
    func exportBugReport(userDescription: String) -> BugReport? {
        guard let logData = SecureLogStorage.shared.exportLogsForBugReport() else {
            return nil
        }

        return BugReport(
            sessionID: sessionID,
            appVersion: Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            buildNumber: Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown",
            osVersion: ProcessInfo.processInfo.operatingSystemVersionString,
            deviceModel: deviceModel(),
            userDescription: userDescription,
            logData: logData,
            timestamp: Date()
        )
    }

    private func deviceModel() -> String {
        var systemInfo = utsname()
        uname(&systemInfo)
        let modelCode = withUnsafePointer(to: &systemInfo.machine) {
            $0.withMemoryRebound(to: CChar.self, capacity: 1) {
                String(validatingUTF8: $0)
            }
        }
        return modelCode ?? "unknown"
    }
}

// MARK: - Supporting Types

enum AuthEvent {
    case loginAttempt
    case loginSuccess
    case loginFailure(reason: String)
    case logoutAttempt
    case logoutSuccess
    case signupSuccess
    case signupFailure(reason: String)
    case tokenRefreshAttempt
    case tokenRefreshSuccess
    case tokenRefreshFailure(reason: String)
    case sessionExpired
    case unauthorized
    case accountLocked
    case mfaRequired
    case passwordResetRequested

    var description: String {
        switch self {
        case .loginAttempt:                     return "Login attempted"
        case .loginSuccess:                     return "Login successful"
        case .loginFailure(let reason):         return "Login failed: \(reason)"
        case .logoutAttempt:                    return "Logout attempted"
        case .logoutSuccess:                    return "Logout successful"
        case .signupSuccess:                    return "Signup successful"
        case .signupFailure(let reason):        return "Signup failed: \(reason)"
        case .tokenRefreshAttempt:              return "Token refresh attempted"
        case .tokenRefreshSuccess:              return "Token refresh successful"
        case .tokenRefreshFailure(let reason):  return "Token refresh failed: \(reason)"
        case .sessionExpired:                   return "Session expired"
        case .unauthorized:                     return "Unauthorized access"
        case .accountLocked:                    return "Account locked"
        case .mfaRequired:                      return "MFA required"
        case .passwordResetRequested:           return "Password reset requested"
        }
    }
}

enum DataChangeType: String {
    case created = "created"
    case updated = "updated"
    case deleted = "deleted"
    case synced = "synced"
}

struct BugReport {
    let sessionID: String
    let appVersion: String
    let buildNumber: String
    let osVersion: String
    let deviceModel: String
    let userDescription: String
    let logData: Data
    let timestamp: Date
}

// MARK: - Network Logger Middleware (URLSession Integration)

final class NetworkLogger {

    static let shared = NetworkLogger()
    private let logger = AppLogger.shared
    private let performanceTracker = PerformanceTracker.shared

    private init() {}

    /// Wraps a URLSession data task with logging
    func loggedDataTask(
        session: URLSession,
        request: URLRequest,
        completion: @escaping (Data?, URLResponse?, Error?) -> Void
    ) -> URLSessionDataTask {

        let method = request.httpMethod ?? "GET"
        let url = request.url ?? URL(string: "unknown")!

        // Log request (redacted)
        var bodyDict: [String: Any]?
        if let bodyData = request.httpBody {
            bodyDict = try? JSONSerialization.jsonObject(with: bodyData) as? [String: Any]
        }

        logger.logAPIRequest(
            method: method,
            url: url,
            headers: request.allHTTPHeaderFields,
            bodyPayload: bodyDict
        )

        let operationID = performanceTracker.begin(
            "\(method) \(url.path)",
            category: .networking,
            metadata: ["method": method, "path": url.path]
        )

        let startTime = CFAbsoluteTimeGetCurrent()

        return session.dataTask(with: request) { [weak self] data, response, error in
            let duration = CFAbsoluteTimeGetCurrent() - startTime
            self?.performanceTracker.end(operationID)

            let statusCode = (response as? HTTPURLResponse)?.statusCode ?? 0

            var responseDict: [String: Any]?
            if let data = data {
                responseDict = try? JSONSerialization.jsonObject(with: data) as? [String: Any]
            }

            self?.logger.logAPIResponse(
                method: method,
                url: url,
                statusCode: statusCode,
                duration: duration,
                error: error,
                responsePayload: responseDict
            )

            completion(data, response, error)
        }
    }
}

// MARK: - Convenience Global Functions

func logInfo(_ message: String, category: LogCategory = .analytics, metadata: [String: String]? = nil,
             file: String = #file, function: String = #function, line: Int = #line) {
    AppLogger.shared.log(level: .info, category: category, message: message, metadata: metadata,
                         file: file, function: function, line: line)
}

func logDebug(_ message: String, category: LogCategory = .analytics, metadata: [String: String]? = nil,
              file: String = #file, function: String = #function, line: Int = #line) {
    AppLogger.shared.log(level: .debug, category: category, message: message, metadata: metadata,
                         file: file, function: function, line: line)
}

func logWarning(_ message: String, category: LogCategory = .analytics, metadata: [String: String]? = nil,
                file: String = #file, function: String = #function, line: Int = #line) {
    AppLogger.shared.log(level: .warning, category: category, message: message, metadata: metadata,
                         file: file, function: function, line: line)
}

func logError(_ error: Error, context: String? = nil, metadata: [String: String]? = nil,
              file: String = #file, function: String = #function, line: Int = #line) {
    AppLogger.shared.logError(error, context: context, metadata: metadata,
                              file: file, function: function, line: line)
}


